const cfg = $json;
const now = new Date().toISOString();
const slugify = value => String(value || '').toLowerCase().replace(/[^a-z0-9|]+/g, '-').replace(/^-+|-+$/g, '');
let cities;
let keywords;
try {
  cities = JSON.parse(cfg.citiesJson || '[]');
  keywords = JSON.parse(cfg.keywordsJson || '[]');
} catch (error) {
  throw new Error(`Invalid workflow configuration JSON: ${error.message}`);
}
if (!Array.isArray(cities) || !Array.isArray(keywords)) {
  throw new Error('Workflow configuration must provide citiesJson and keywordsJson as JSON arrays');
}
const rows = [];
for (const city of cities) {
  for (const keyword of keywords) {
    const sourceTemplate = keyword;
    const operationalKeyword = keyword === 'med spa near me' ? 'med spa' : keyword;
    const queryText = cfg.queryPattern
      .replace('{keyword}', operationalKeyword)
      .replace('{city}', city.city)
      .replace('{state}', city.state);
    const searchJobId = slugify([city.city, city.state, sourceTemplate, 'v1'].join('|'));
    rows.push({
      json: {
        search_job_id: searchJobId,
        queue_key: searchJobId,
        city: city.city,
        state: city.state,
        state_code: city.state_code,
        keyword: sourceTemplate,
        source_query_template: sourceTemplate,
        source_query_executed: queryText,
        query_text: queryText,
        status: 'READY',
        attempt_count: 0,
        max_attempts: Number(cfg.maxAttempts || 3),
        last_run_at: '',
        next_retry_at: '',
        lease_owner: '',
        lease_until: '',
        apify_run_id: '',
        apify_dataset_id: '',
        result_count: '',
        last_error_code: '',
        last_error: '',
        created_at: now,
        updated_at: now,
        completed_at: '',
        schema_version: 'v1',
      },
    });
  }
}
return rows;
